481→type regularBucketIterator struct {
482→	baseBucketIterator[uint64, int64]
483→}
484→
485→func newRegularBucketIterator(spans []Span, buckets []int64, schema int32, positive bool, customValues []float64) regularBucketIterator {
486→	i := baseBucketIterator[uint64, int64]{
487→		schema:       schema,
488→		spans:        spans,
489→		buckets:      buckets,
490→		positive:     positive,
491→		customValues: customValues,
492→	}
493→	return regularBucketIterator{i}
494→}
495→
496→func (r *regularBucketIterator) Next() bool {
497→	if r.spansIdx >= len(r.spans) {
498→		return false
499→	}
500→	span := r.spans[r.spansIdx]
501→	// Seed currIdx for the first bucket.
502→	if r.bucketsIdx == 0 {
503→		r.currIdx = span.Offset
504→	} else {
505→		r.currIdx++
506→	}
507→	for r.idxInSpan >= span.Length {
508→		// We have exhausted the current span and have to find a new
509→		// one. We'll even handle pathologic spans of length 0.
510→		r.idxInSpan = 0
511→		r.spansIdx++
512→		if r.spansIdx >= len(r.spans) {
513→			return false
514→		}
515→		span = r.spans[r.spansIdx]
516→		r.currIdx += span.Offset
517→	}
518→
519→	// This protects against index out of range panic, which
520→	// can only happen with an invalid histogram.
521→	if r.bucketsIdx >= len(r.buckets) {
522→		return false
523→	}
524→	r.currCount += r.buckets[r.bucketsIdx]
525→	r.idxInSpan++
526→	r.bucketsIdx++
527→	return true
528→}
529→
530→type cumulativeBucketIterator struct {
531→	h *Histogram
532→
533→	posSpansIdx   int    // Index in h.PositiveSpans we are in. -1 means 0 bucket.
534→	posBucketsIdx int    // Index in h.PositiveBuckets.
535→	idxInSpan     uint32 // Index in the current span. 0 <= idxInSpan < span.Length.
536→
537→	initialized         bool
538→	currIdx             int32   // The actual bucket index after decoding from spans.
539→	currUpper           float64 // The upper boundary of the current bucket.
540→	currCount           int64   // Current non-cumulative count for the current bucket. Does not apply for empty bucket.
541→	currCumulativeCount uint64  // Current "cumulative" count for the current bucket.
542→
543→	// Between 2 spans there could be some empty buckets which
544→	// still needs to be counted for cumulative buckets.
545→	// When we hit the end of a span, we use this to iterate
546→	// through the empty buckets.
547→	emptyBucketCount int32
548→}
549→
550→func (c *cumulativeBucketIterator) Next() bool {
551→	if c.posSpansIdx == -1 {
552→		// Zero bucket.
553→		c.posSpansIdx++
554→		if c.h.ZeroCount == 0 {
555→			return c.Next()
556→		}
557→
558→		c.currUpper = c.h.ZeroThreshold
559→		c.currCount = int64(c.h.ZeroCount)
560→		c.currCumulativeCount = uint64(c.currCount)
561→		return true
562→	}
563→
564→	if c.posSpansIdx >= len(c.h.PositiveSpans) {
565→		return false
566→	}
567→
568→	if c.emptyBucketCount > 0 {
569→		// We are traversing through empty buckets at the moment.
570→		c.currUpper = getBound(c.currIdx, c.h.Schema, c.h.CustomValues)
571→		c.currIdx++
572→		c.emptyBucketCount--
573→		return true
574→	}
575→
576→	span := c.h.PositiveSpans[c.posSpansIdx]
577→	if c.posSpansIdx == 0 && !c.initialized {
578→		// Initializing.
579→		c.currIdx = span.Offset
580→		// The first bucket is an absolute value and not a delta with Zero bucket.
581→		c.currCount = 0
582→		c.initialized = true
583→	}
584→
585→	// This protects against index out of range panic, which
586→	// can only happen with an invalid histogram.
587→	if c.posBucketsIdx >= len(c.h.PositiveBuckets) {
588→		return false
589→	}
590→	c.currCount += c.h.PositiveBuckets[c.posBucketsIdx]
591→	c.currCumulativeCount += uint64(c.currCount)
592→	c.currUpper = getBound(c.currIdx, c.h.Schema, c.h.CustomValues)
593→
594→	c.posBucketsIdx++
595→	c.idxInSpan++
596→	c.currIdx++
597→	if c.idxInSpan >= span.Length {
598→		// Move to the next span. This one is done.
599→		c.posSpansIdx++
600→		c.idxInSpan = 0
601→		if c.posSpansIdx < len(c.h.PositiveSpans) {
602→			c.emptyBucketCount = c.h.PositiveSpans[c.posSpansIdx].Offset
603→		}
604→	}
605→
606→	return true
607→}
608→
609→func (c *cumulativeBucketIterator) At() Bucket[uint64] {
610→	return Bucket[uint64]{
611→		Upper:          c.currUpper,
612→		Lower:          math.Inf(-1),
613→		UpperInclusive: true,
614→		LowerInclusive: true,
615→		Count:          c.currCumulativeCount,
616→		Index:          c.currIdx - 1,
617→	}
618→}
619→
620→// ReduceResolution reduces the histogram's spans, buckets into target schema.
621→// An error is returned in the following cases:
622→//   - The target schema is not smaller than the current histogram's schema.
623→//   - The histogram has custom buckets.
624→//   - The target schema is a custom buckets schema.
625→//   - Any spans have an invalid offset.
626→//   - The spans are inconsistent with the number of buckets.
627→func (h *Histogram) ReduceResolution(targetSchema int32) error {
628→	// Note that the follow three returns are not returning a
629→	// histogram.Error because they are programming errors.
630→	if h.UsesCustomBuckets() {
631→		return errors.New("cannot reduce resolution when there are custom buckets")
632→	}
633→	if IsCustomBucketsSchema(targetSchema) {
634→		return errors.New("cannot reduce resolution to custom buckets schema")
635→	}
636→	if targetSchema >= h.Schema {
637→		return fmt.Errorf("cannot reduce resolution from schema %d to %d", h.Schema, targetSchema)
638→	}
639→
640→	var err error
641→
642→	if h.PositiveSpans, h.PositiveBuckets, err = reduceResolution(
643→		h.PositiveSpans, h.PositiveBuckets, h.Schema, targetSchema, true, true,
644→	); err != nil {
645→		return err
646→	}
647→	if h.NegativeSpans, h.NegativeBuckets, err = reduceResolution(
648→		h.NegativeSpans, h.NegativeBuckets, h.Schema, targetSchema, true, true,
649→	); err != nil {
650→		return err
651→	}
652→	h.Schema = targetSchema
653→	return nil
654→}
